import{_ as i,c as e,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Функции платформы: модели и квоты | opencode-antigravity-auth","description":"Узнайте о типах моделей и двойной системе квот в плагине Antigravity Auth. Освойте выбор моделей, настройку Thinking и Google Search, оптимизируйте использование квот.","frontmatter":{"title":"Функции платформы: модели и квоты | opencode-antigravity-auth","sidebarTitle":"Двойная система квот","subtitle":"Функции платформы: модели и квоты","description":"Узнайте о типах моделей и двойной системе квот в плагине Antigravity Auth. Освойте выбор моделей, настройку Thinking и Google Search, оптимизируйте использование квот.","order":2},"headers":[],"relativePath":"ru/NoeFabris/opencode-antigravity-auth/platforms/index.md","filePath":"ru/NoeFabris/opencode-antigravity-auth/platforms/index.md"}'),n={name:"ru/NoeFabris/opencode-antigravity-auth/platforms/index.md"};function r(o,a,h,d,s,u){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="функции-платформы" tabindex="-1">Функции платформы <a class="header-anchor" href="#функции-платформы" aria-label="Permalink to &quot;Функции платформы&quot;">​</a></h1><p>Эта глава поможет вам глубже понять модели, систему квот и функции платформы, поддерживаемые плагином Antigravity Auth. Вы научитесь выбирать подходящую модель, настраивать возможности Thinking, включать Google Search и максимизировать использование квот.</p><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Перед началом убедитесь</p><p>Перед изучением этой главы убедитесь, что вы завершили:</p><ul><li><a href="./../start/quick-install/">Быстрая установка</a> — установка плагина и первая аутентификация</li><li><a href="./../start/first-request/">Первый запрос</a> — успешная отправка первого запроса к модели</li></ul></div><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Изучайте материалы в следующем порядке —循序渐进掌握平台功能：</p><h3 id="_1-доступные-модели" tabindex="-1">1. <a href="./available-models/">Доступные модели</a> <a class="header-anchor" href="#_1-доступные-модели" aria-label="Permalink to &quot;1. [Доступные модели](./available-models/)&quot;">​</a></h3><p>Узнайте обо всех доступных моделях и их конфигурациях вариантов</p><ul><li>Ознакомьтесь с Claude Opus 4.5, Sonnet 4.5 и Gemini 3 Pro/Flash</li><li>Поймите распределение моделей между двумя пулами квот Antigravity и Gemini CLI</li><li>Освойте использование параметра <code>--variant</code></li></ul><h3 id="_2-двоиная-система-квот" tabindex="-1">2. <a href="./dual-quota-system/">Двойная система квот</a> <a class="header-anchor" href="#_2-двоиная-система-квот" aria-label="Permalink to &quot;2. [Двойная система квот](./dual-quota-system/)&quot;">​</a></h3><p>Поймите принцип работы двойной системы квот Antigravity и Gemini CLI</p><ul><li>Узнайте, как каждая учётная запись обладает двумя независимыми пулами квот Gemini</li><li>Включите автоматическую конфигурацию fallback для удвоения квот</li><li>Явно укажите использование определённого пула квот для конкретной модели</li></ul><h3 id="_3-google-search-grounding" tabindex="-1">3. <a href="./google-search-grounding/">Google Search Grounding</a> <a class="header-anchor" href="#_3-google-search-grounding" aria-label="Permalink to &quot;3. [Google Search Grounding](./google-search-grounding/)&quot;">​</a></h3><p>Включите Google Search для моделей Gemini, чтобы повысить точность фактов</p><ul><li>Позвольте Gemini искать актуальную информацию в сети</li><li>Настройте порог поиска для управления частотой поисков</li><li>Выберите подходящую конфигурацию в зависимости от требований задачи</li></ul><h3 id="_4-thinking-модели" tabindex="-1">4. <a href="./thinking-models/">Thinking модели</a> <a class="header-anchor" href="#_4-thinking-модели" aria-label="Permalink to &quot;4. [Thinking модели](./thinking-models/)&quot;">​</a></h3><p>Освойте конфигурацию и использование Thinking моделей Claude и Gemini 3</p><ul><li>Настройте thinking budget для Claude</li><li>Используйте thinking level Gemini 3 (minimal/low/medium/high)</li><li>Поймите interleaved thinking и стратегию сохранения блоков размышлений</li></ul><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы вы можете продолжить обучение:</p><ul><li><a href="./../advanced/multi-account-setup/">Настройка нескольких аккаунтов</a> — настройка нескольких учётных записей Google для объединения пулов квот и балансировки нагрузки</li><li><a href="./../advanced/account-selection-strategies/">Стратегии выбора аккаунта</a> — освоение лучших практик трёх стратегий: sticky, round-robin и hybrid</li><li><a href="./../advanced/configuration-guide/">Руководство по конфигурации</a> — освоение всех параметров конфигурации для настройки поведения плагина по требованиям</li></ul>',21)])])}const m=i(n,[["render",r]]);export{g as __pageData,m as default};
